-- Ken's Hardened V2 Fix

local b64_0xI1I1II = {}
local char_0xl1I1I1='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xIllIII=1,#char_0xl1I1I1 do b64_0xI1I1II[char_0xl1I1I1:sub(i_0xIllIII,i_0xIllIII)] = i_0xIllIII - 1 end

function b64_0xI1I1II.dec_0xl1III1(d_0xlI1lIl)
    d_0xlI1lIl = string.gsub(d_0xlI1lIl, '[^'..char_0xl1I1I1..'=]', '')
    local r_0xIlIllI = {}
    for i_0xIllIII=1, #d_0xlI1lIl, 4 do
        local c_0xlIIIlI = b64_0xI1I1II[d_0xlI1lIl:sub(i_0xIllIII,i_0xIllIII)] or 0
        local c_0xllI1lI = b64_0xI1I1II[d_0xlI1lIl:sub(i_0xIllIII+1,i_0xIllIII+1)] or 0
        local c_0xl1IIll, c_0xII1I1l = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xlI1lIl:sub(i_0xIllIII+2,i_0xIllIII+2)
        if ch3 == "=" then has3 = false else c_0xl1IIll = b64_0xI1I1II[ch3] or 0 end
        local ch4 = d_0xlI1lIl:sub(i_0xIllIII+3,i_0xIllIII+3)
        if ch4 == "=" then has4 = false else c_0xII1I1l = b64_0xI1I1II[ch4] or 0 end
        local b_0xlIIlll = c_0xlIIIlI * (2^18) + c_0xllI1lI * (2^12) + c_0xl1IIll * (2^6) + c_0xII1I1l
        local b_0xll1II1 = math.floor(b_0xlIIlll / (2^16)) % (2^8)
        local b_0xIIlll1 = math.floor(b_0xlIIlll / (2^8)) % (2^8)
        local b_0xIIl1Il = b_0xlIIlll % (2^8)
        table.insert(r_0xIlIllI, string.char(b_0xll1II1))
        if has3 then table.insert(r_0xIlIllI, string.char(b_0xIIlll1)) end
        if has4 then table.insert(r_0xIlIllI, string.char(b_0xIIl1Il)) end
    end
    return table.concat(r_0xIlIllI)
end


local function bxor_0x1l11Il(a_0xI11lIl,b_0x1I11lI)
    if bit32 then return bit32.bxor(a_0xI11lIl,b_0x1I11lI) end
    local r_0x1IIIl1 = 0
    for i_0xlI1Ill = 0, 7 do
        local x_0x1l1lll = a_0xI11lIl % 2
        local y_0xlII1Il = b_0x1I11lI % 2
        if x_0x1l1lll ~= y_0xlII1Il then r_0x1IIIl1 = r_0x1IIIl1 + (2^i_0xlI1Ill) end
        a_0xI11lIl = math.floor(a_0xI11lIl / 2)
        b_0x1I11lI = math.floor(b_0x1I11lI / 2)
    end
    return r_0x1IIIl1
end


local function bxor_str_0xIl1I1l(s_0x1l1111, k_0xllll11)
    local r_0xIIlIll = {}
    for i_0xIIlII1=1, #s_0x1l1111 do
        local b_0xllIIlI = string.byte(s_0x1l1111, i_0xIIlII1)
        local kb_0x1lIlIl = string.byte(k_0xllll11, (i_0xIIlII1-1) % #k_0xllll11 + 1)
        r_0xIIlIll[i_0xIIlII1] = string.char(bxor_0x1l11Il(b_0xllIIlI, kb_0x1lIlIl))
    end
    return table.concat(r_0xIIlIll)
end


local function getkeys_0xIIIIll()
    local seed = b64_0xI1I1II.dec_0xl1III1("eXo2Z2xUeFk=")
    local k1_enc = b64_0xI1I1II.dec_0xl1III1("LCsOCDoiDB8=")
    local k2_enc = b64_0xI1I1II.dec_0xl1III1("Hy4DDyo/Mx4=")
    return bxor_str_0xIl1I1l(k1_enc, seed), bxor_str_0xIl1I1l(k2_enc, seed)
end


local function cff_0xIIll11(a_0xIIIlll)
    local st_0x11lIlI = 0
    local res_0xlllIl1 = a_0xIIIlll
    while true do
        if st_0x11lIlI == 0 then
            res_0xlllIl1 = res_0xlllIl1 + 1
            st_0x11lIlI = 1
        elseif st_0x11lIlI == 1 then
            res_0xlllIl1 = res_0xlllIl1 * 2
            st_0x11lIlI = 2
        elseif st_0x11lIlI == 2 then
            res_0xlllIl1 = res_0xlllIl1 - 3
            st_0x11lIlI = 3
        else
            break
        end
    end
    return res_0xlllIl1
end


local function chain_0xII1I1I(x) return x*2 end
local function chain_0xlIIl1I(x) return chain_0xII1I1I(x)+1 end


local d_0x1II11I = {
  {op=255, val="", is_enc=true},
}
local pc_0xlIl1ll = 1
local stk_0x1IllI1 = {}
stk_0x1IllI1._jmp = nil


local disp_0x11I11l = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIIIIll()

local state_0x1II1l1 = 0
while true do
    if state_0x1II1l1 == 0 then  -- FETCH
        if pc_0xlIl1ll > #d_0x1II11I then break end
        local inst = d_0x1II11I[pc_0xlIl1ll]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xI1I1II.dec_0xl1III1(val)
            d = bxor_str_0xIl1I1l(d, k2)
            val = bxor_str_0xIl1I1l(d, k1)
        end
        stk_0x1IllI1._jmp = nil
        pc_0xlIl1ll = pc_0xlIl1ll + 1
        cur_op_0x11IIIl = opcode
        cur_val_0x11llIl = val
        state_0x1II1l1 = 1

    elseif state_0x1II1l1 == 1 then  -- EXECUTE
        local handler = disp_0x11I11l[cur_op_0x11IIIl]
        if handler then
            handler(stk_0x1IllI1, cur_val_0x11llIl)
        end
        if stk_0x1IllI1._jmp then
            pc_0xlIl1ll = pc_0xlIl1ll + stk_0x1IllI1._jmp
        end
        state_0x1II1l1 = 0
    else
        break
    end
end
